    function managePlayer(uint256 _pID, LOLdatasets.EventReturns memory _eventData_)
        private
        returns (LOLdatasets.EventReturns)
    {


        if (plyr_[_pID].lrnd != 0)
            updateGenVault(_pID, plyr_[_pID].lrnd);


