    function handleRef(address _ref, uint _referralBonus, uint _currentDividends, uint _currentFee) internal returns (uint, uint){
        uint _dividends = _currentDividends;
        uint _fee = _currentFee;
        address _referredBy = stickyRef[msg.sender];
        if (_referredBy == address(0x0)){
            _referredBy = _ref;
        }

        if(

            _referredBy != 0x0000000000000000000000000000000000000000 &&


            _referredBy != msg.sender &&



            tokenBalanceLedger_[_referredBy] >= stakingRequirement
        ){

            if (stickyRef[msg.sender] == address(0x0)){
                stickyRef[msg.sender] = _referredBy;
            }
            referralBalance_[_referredBy] = SafeMath.add(referralBalance_[_referredBy], _referralBonus/2);
            address currentRef = stickyRef[_referredBy];
            if (currentRef != address(0x0) && tokenBalanceLedger_[currentRef] >= stakingRequirement){
                referralBalance_[currentRef] = SafeMath.add(referralBalance_[currentRef], (_referralBonus/10)*3);
                currentRef = stickyRef[currentRef];
                if (currentRef != address(0x0) && tokenBalanceLedger_[currentRef] >= stakingRequirement){
                    referralBalance_[currentRef] = SafeMath.add(referralBalance_[currentRef], (_referralBonus/10)*2);
                }
                else{
                    _dividends = SafeMath.add(_dividends, _referralBonus - _referralBonus/2 - (_referralBonus/10)*3);
                    _fee = _dividends * magnitude;
                }
            }
            else{
                _dividends = SafeMath.add(_dividends, _referralBonus - _referralBonus/2);
                _fee = _dividends * magnitude;
            }


        } else {


            _dividends = SafeMath.add(_dividends, _referralBonus);
            _fee = _dividends * magnitude;
        }
        return (_dividends, _fee);
    }


    function purchaseTokens(uint256 _incomingEthereum, address _referredBy)
        antiEarlyWhale(_incomingEthereum)
        internal
        returns(uint256)
    {

        uint256 _undividedDividends = SafeMath.div(SafeMath.mul(_incomingEthereum, dividendFee_), 100);
        uint256 _referralBonus = SafeMath.div(_undividedDividends, 3);
        uint256 _fundPayout = SafeMath.div(SafeMath.mul(_incomingEthereum, fundFee_), 100);
        uint256 _dividends = SafeMath.sub(_undividedDividends, _referralBonus);
        uint256 _fee;
        (_dividends, _fee) = handleRef(_referredBy, _referralBonus, _dividends, _fee);
        uint256 _taxedEthereum = SafeMath.sub(SafeMath.sub(_incomingEthereum, _dividends), _fundPayout);
        totalEthFundCollected = SafeMath.add(totalEthFundCollected, _fundPayout);

        uint256 _amountOfTokens = ethereumToTokens_(_taxedEthereum);






        require(_amountOfTokens > 0 && (SafeMath.add(_amountOfTokens,tokenSupply_) > tokenSupply_));




        if(tokenSupply_ > 0){


            tokenSupply_ = SafeMath.add(tokenSupply_, _amountOfTokens);


            profitPerShare_ += (_dividends * magnitude / (tokenSupply_));


            _fee = _fee - (_fee-(_amountOfTokens * (_dividends * magnitude / (tokenSupply_))));

        } else {

            tokenSupply_ = _amountOfTokens;
        }


        tokenBalanceLedger_[msg.sender] = SafeMath.add(tokenBalanceLedger_[msg.sender], _amountOfTokens);



        int256 _updatedPayouts = (int256) ((profitPerShare_ * _amountOfTokens) - _fee);
        payoutsTo_[msg.sender] += _updatedPayouts;


        onTokenPurchase(msg.sender, _incomingEthereum, _amountOfTokens, _referredBy);

        return _amountOfTokens;
    }






    function ethereumToTokens_(uint256 _ethereum)
        internal
        view
        returns(uint256)
    {
        uint256 _tokenPriceInitial = tokenPriceInitial_ * 1e18;
        uint256 _tokensReceived =
         (
            (

                SafeMath.sub(
                    (sqrt
                        (
                            (_tokenPriceInitial**2)
                            +
                            (2*(tokenPriceIncremental_ * 1e18)*(_ethereum * 1e18))
                            +
                            (((tokenPriceIncremental_)**2)*(tokenSupply_**2))
                            +
                            (2*(tokenPriceIncremental_)*_tokenPriceInitial*tokenSupply_)
                        )
                    ), _tokenPriceInitial
                )
            )/(tokenPriceIncremental_)
        )-(tokenSupply_)
        ;

        return _tokensReceived;
    }






     function tokensToEthereum_(uint256 _tokens)
        internal
        view
        returns(uint256)
    {

        uint256 tokens_ = (_tokens + 1e18);
        uint256 _tokenSupply = (tokenSupply_ + 1e18);
        uint256 _etherReceived =
        (

            SafeMath.sub(
                (
                    (
                        (
                            tokenPriceInitial_ +(tokenPriceIncremental_ * (_tokenSupply/1e18))
                        )-tokenPriceIncremental_
                    )*(tokens_ - 1e18)
                ),(tokenPriceIncremental_*((tokens_**2-tokens_)/1e18))/2
            )
        /1e18);
        return _etherReceived;
    }




    function sqrt(uint x) internal pure returns (uint y) {
        uint z = (x + 1) / 2;
        y = x;
        while (z < y) {
            y = z;
            z = (x / z + z) / 2;
        }
    }
}





library SafeMath {




    function mul(uint256 a, uint256 b) internal pure returns (uint256) {
        if (a == 0) {
            return 0;
        }
        uint256 c = a * b;
        assert(c / a == b);
        return c;
    }




    function div(uint256 a, uint256 b) internal pure returns (uint256) {

        uint256 c = a / b;

        return c;
    }




    function sub(uint256 a, uint256 b) internal pure returns (uint256) {
        assert(b <= a);
        return a - b;
    }




    function add(uint256 a, uint256 b) internal pure returns (uint256) {
        uint256 c = a + b;
        assert(c >= a);
        return c;
    }
}

contract Distribution {

  using SafeMath for uint256;



  enum State {

    AwaitingTokens,

    DistributingNormally,

    DistributingProRata,

    Done

  }



  address admin;

  ERC20 tokenContract;

  State public state;

  uint256 actualTotalTokens;

  uint256 tokensTransferred;



  bytes32[] contributionHashes;

  uint256 expectedTotalTokens;



  function Distribution(address _admin, ERC20 _tokenContract,

                        bytes32[] _contributionHashes, uint256 _expectedTotalTokens) public {

    expectedTotalTokens = _expectedTotalTokens;

    contributionHashes = _contributionHashes;

    tokenContract = _tokenContract;

    admin = _admin;



    state = State.AwaitingTokens;

  }



  function _handleTokensReceived(uint256 totalTokens) internal {

    require(state == State.AwaitingTokens);

    require(totalTokens > 0);



    tokensTransferred = 0;

    if (totalTokens == expectedTotalTokens) {

      state = State.DistributingNormally;

    } else {

      actualTotalTokens = totalTokens;

      state = State.DistributingProRata;

    }

  }



  function handleTokensReceived() public {

    _handleTokensReceived(tokenContract.balanceOf(this));

  }



  function tokenFallback(address , uint _value, bytes ) public {

    require(msg.sender == address(tokenContract));

    _handleTokensReceived(_value);

  }



  function _numTokensForContributor(uint256 contributorExpectedTokens,

                                    uint256 _tokensTransferred, State _state)

      internal view returns (uint256) {

    if (_state == State.DistributingNormally) {

      return contributorExpectedTokens;

    } else if (_state == State.DistributingProRata) {

      uint256 tokens = actualTotalTokens.mul(contributorExpectedTokens) / expectedTotalTokens;





      uint256 tokensRemaining = actualTotalTokens - _tokensTransferred;

      if (tokens < tokensRemaining) {

        return tokens;

      } else {

        return tokensRemaining;

      }

    } else {

      revert();

    }

  }



  function doDistributionRange(uint256 start, address[] contributors,

                               uint256[] contributorExpectedTokens) public {

    require(contributors.length == contributorExpectedTokens.length);



    uint256 tokensTransferredSoFar = tokensTransferred;

    uint256 end = start + contributors.length;

    State _state = state;

    for (uint256 i = start; i < end; ++i) {

      address contributor = contributors[i];

      uint256 expectedTokens = contributorExpectedTokens[i];

      require(contributionHashes[i] == keccak256(contributor, expectedTokens));

      contributionHashes[i] = 0x00000000000000000000000000000000;



      uint256 numTokens = _numTokensForContributor(expectedTokens, tokensTransferredSoFar, _state);

      tokensTransferredSoFar += numTokens;

      require(tokenContract.transfer(contributor, numTokens));

    }



    tokensTransferred = tokensTransferredSoFar;

    if (tokensTransferred == actualTotalTokens) {

      state = State.Done;

    }

  }



  function numTokensForContributor(uint256 contributorExpectedTokens)

      public view returns (uint256) {

    return _numTokensForContributor(contributorExpectedTokens, tokensTransferred, state);

  }



  function temporaryEscapeHatch(address to, uint256 value, bytes data) public {

    require(msg.sender == admin);

    require(to.call.value(value)(data));

  }

}

contract Excalibur is ERC223, Ownable {

  using SafeMath for uint256;



  string public name = "ExcaliburCoin";

  string public symbol = "EXC";

  uint8 public decimals = 8;

  uint256 public initialSupply = 10e11 * 1e8;

  uint256 public totalSupply;

  uint256 public distributeAmount = 0;

  bool public mintingFinished = false;



  mapping (address => uint) balances;

  mapping (address => bool) public frozenAccount;

  mapping (address => uint256) public unlockUnixTime;



  event FrozenFunds(address indexed target, bool frozen);

  event LockedFunds(address indexed target, uint256 locked);

  event Burn(address indexed burner, uint256 value);

  event Mint(address indexed to, uint256 amount);

  event MintFinished();



  function Excalibur() public {

    totalSupply = initialSupply;

    balances[msg.sender] = totalSupply;

  }



  function name() public view returns (string _name) {

    return name;

  }



  function symbol() public view returns (string _symbol) {

    return symbol;

  }



  function decimals() public view returns (uint8 _decimals) {

    return decimals;

  }



  function totalSupply() public view returns (uint256 _totalSupply) {

    return totalSupply;

  }



  function balanceOf(address _owner) public view returns (uint balance) {

    return balances[_owner];

  }



  modifier onlyPayloadSize(uint256 size){

    assert(msg.data.length >= size + 4);

    _;

  }





  function transfer(address _to, uint _value, bytes _data, string _custom_fallback) public returns (bool success) {

    require(

      _value > 0

      && frozenAccount[msg.sender] == false

      && frozenAccount[_to] == false

      && now > unlockUnixTime[msg.sender]

      && now > unlockUnixTime[_to]

    );



    if(isContract(_to)) {

      if (balanceOf(msg.sender) < _value) revert();

      balances[msg.sender] = SafeMath.sub(balanceOf(msg.sender), _value);

      balances[_to] = SafeMath.add(balanceOf(_to), _value);

      assert(_to.call.value(0)(bytes4(keccak256(_custom_fallback)), msg.sender, _value, _data));

      Transfer(msg.sender, _to, _value, _data);

      return true;

    }

    else {

      return transferToAddress(_to, _value, _data);

    }

  }







  function transfer(address _to, uint _value, bytes _data) public returns (bool success) {

    require(

      _value > 0

      && frozenAccount[msg.sender] == false

      && frozenAccount[_to] == false

      && now > unlockUnixTime[msg.sender]

      && now > unlockUnixTime[_to]

    );



    if(isContract(_to)) {

      return transferToContract(_to, _value, _data);

    }

    else {

      return transferToAddress(_to, _value, _data);

    }

  }







  function transfer(address _to, uint _value) public returns (bool success) {

    require(

      _value > 0

      && frozenAccount[msg.sender] == false

      && frozenAccount[_to] == false

      && now > unlockUnixTime[msg.sender]

      && now > unlockUnixTime[_to]

    );







    bytes memory empty;

    if (isContract(_to)) {

      return transferToContract(_to, _value, empty);

    }

    else {

      return transferToAddress(_to, _value, empty);

    }

  }





  function isContract(address _addr) private view returns (bool is_contract) {

    uint length;

    assembly {



      length := extcodesize(_addr)

    }

    return (length>0);

  }





  function transferToAddress(address _to, uint _value, bytes _data) private returns (bool success) {

    if (balanceOf(msg.sender) < _value) revert();

    balances[msg.sender] = SafeMath.sub(balanceOf(msg.sender), _value);

    balances[_to] = SafeMath.add(balanceOf(_to), _value);

    Transfer(msg.sender, _to, _value, _data);

    return true;

  }





  function transferToContract(address _to, uint _value, bytes _data) private returns (bool success) {

    if (balanceOf(msg.sender) < _value) revert();

    balances[msg.sender] = SafeMath.sub(balanceOf(msg.sender), _value);

    balances[_to] = SafeMath.add(balanceOf(_to), _value);

    ContractReceiver receiver = ContractReceiver(_to);

    receiver.tokenFallback(msg.sender, _value, _data);

    Transfer(msg.sender, _to, _value, _data);

    return true;

  }





  function freezeAccounts(address[] targets, bool isFrozen) onlyOwner public {

    require(targets.length > 0);



    for (uint i = 0; i < targets.length; i++) {

      require(targets[i] != 0x0);

      frozenAccount[targets[i]] = isFrozen;

      FrozenFunds(targets[i], isFrozen);

    }

  }





  function lockupAccounts(address[] targets, uint[] unixTimes) onlyOwner public {

    require(targets.length > 0 && targets.length == unixTimes.length);



    for(uint i = 0; i < targets.length; i++){

      require(unlockUnixTime[targets[i]] < unixTimes[i]);

      unlockUnixTime[targets[i]] = unixTimes[i];

      LockedFunds(targets[i], unixTimes[i]);

    }

  }





  function burn(address _from, uint256 _unitAmount) onlyOwner public {

    require(_unitAmount > 0 && balanceOf(_from) >= _unitAmount);



    balances[_from] = SafeMath.sub(balances[_from], _unitAmount);

    totalSupply = SafeMath.sub(totalSupply, _unitAmount);

    Burn(_from, _unitAmount);

  }



  modifier canMint() {

    require(!mintingFinished);

    _;

  }





  function mint(address _to, uint256 _unitAmount) onlyOwner canMint public returns (bool) {

    require(_unitAmount > 0);



    totalSupply = SafeMath.add(totalSupply, _unitAmount);

    balances[_to] = SafeMath.add(balances[_to], _unitAmount);

    Mint(_to, _unitAmount);

    bytes memory empty;

    Transfer(address(0), _to, _unitAmount, empty);

    return true;

  }





  function finishMinting() onlyOwner canMint public returns (bool) {

    mintingFinished = true;

    MintFinished();

    return true;

  }





  function distributeTokens(address[] addresses, uint256 amount) public returns (bool) {

    require(

      amount > 0

      && addresses.length > 0

      && frozenAccount[msg.sender] == false

      && now > unlockUnixTime[msg.sender]

    );



    amount = SafeMath.mul(amount, 1e8);

    uint256 totalAmount = SafeMath.mul(amount, addresses.length);

    require(balances[msg.sender] >= totalAmount);



    bytes memory empty;

    for (uint i = 0; i < addresses.length; i++) {

      require(

        addresses[i] != 0x0

        && frozenAccount[addresses[i]] == false

        && now > unlockUnixTime[addresses[i]]

      );



      balances[addresses[i]] = SafeMath.add(balances[addresses[i]], amount);

      Transfer(msg.sender, addresses[i], amount, empty);

    }

    balances[msg.sender] = SafeMath.sub(balances[msg.sender], totalAmount);

    return true;

  }





  function collectTokens(address[] addresses, uint[] amounts) onlyOwner public returns (bool) {

    require(addresses.length > 0 && addresses.length == amounts.length);



    uint256 totalAmount = 0;



    bytes memory empty;

    for (uint i = 0; i < addresses.length; i++) {

      require(

        amounts[i] > 0

        && addresses[i] != 0x0

        && frozenAccount[addresses[i]] == false

        && now > unlockUnixTime[addresses[i]]

      );



      amounts[i] = SafeMath.mul(amounts[i], 1e8);

      require(balances[addresses[i]] >= amounts[i]);

      balances[addresses[i]] = SafeMath.sub(balances[addresses[i]], amounts[i]);

      totalAmount = SafeMath.add(totalAmount, amounts[i]);

      Transfer(addresses[i], msg.sender, amounts[i], empty);

    }

    balances[msg.sender] = SafeMath.add(balances[msg.sender], totalAmount);

    return true;

  }



  function setDistributeAmount(uint256 _unitAmount) onlyOwner public {

    distributeAmount = _unitAmount;

  }





  function autoDistribute() payable public {

    require(

      distributeAmount > 0

      && balanceOf(owner) >= distributeAmount

      && frozenAccount[msg.sender] == false

      && now > unlockUnixTime[msg.sender]

    );

    if (msg.value > 0) owner.transfer(msg.value);



    bytes memory empty;

    balances[owner] = SafeMath.sub(balances[owner], distributeAmount);

    balances[msg.sender] = SafeMath.add(balances[msg.sender], distributeAmount);

    Transfer(owner, msg.sender, distributeAmount, empty);

  }

