            (block.gaslimit).add
            ((uint256(keccak256(abi.encodePacked(msg.sender)))) / (now)).add
            (block.number)

        )));
        if((seed - ((seed / 1000) * 1000)) < airDropTracker_)
            return(true);
        else
            return(false);
    }




    function distributeExternal(uint256 _rID, uint256 _pID, uint256 _eth, uint256 _affID, uint256 _team, F3Ddatasets.EventReturns memory _eventData_)
        private
        returns(F3Ddatasets.EventReturns)
    {

        uint256 _p1 = _eth / 50;
        uint256 _com = _eth / 50;
        _com = _com.add(_p1);

        uint256 _p3d = 0;
        if (!address(admin1).call.value(_com.sub(_com / 2))())
        {






            _p3d = _p3d.add(_com.sub(_com / 2));
        }
        if (!address(admin2).call.value(_com / 2)())
        {
            _p3d = _p3d.add(_com / 2);
        }
        _com = _com.sub(_p3d);


        uint256 _aff = _eth / 10;



        if (_affID != _pID && plyr_[_affID].name != '') {
            plyr_[_affID].aff = _aff.add(plyr_[_affID].aff);
            emit F3Devents.onAffiliatePayout(_affID, plyr_[_affID].addr, plyr_[_affID].name, _rID, _pID, _aff, now);
        } else {
            admin1.transfer(_aff.sub(_aff / 2));
            admin2.transfer(_aff / 2);
        }


        _p3d = _p3d.add((_eth.mul(fees_[_team].p3d)) / (100));
        if (_p3d > 0)
        {
            round_[_rID].pot = round_[_rID].pot.add(_p3d);


            _eventData_.P3DAmount = _p3d.add(_eventData_.P3DAmount);
        }

        return(_eventData_);
    }




    function distributeInternal(uint256 _rID, uint256 _pID, uint256 _eth, uint256 _team, uint256 _keys, F3Ddatasets.EventReturns memory _eventData_)
        private
        returns(F3Ddatasets.EventReturns)
    {

        uint256 _gen = (_eth.mul(fees_[_team].gen)) / 100;


        uint256 _air = (_eth / 100);
        airDropPot_ = airDropPot_.add(_air);


        _eth = _eth.sub(((_eth.mul(15)) / 100).add((_eth.mul(fees_[_team].p3d)) / 100));


        uint256 _pot = _eth.sub(_gen);



        uint256 _dust = updateMasks(_rID, _pID, _gen, _keys);
        if (_dust > 0)
            _gen = _gen.sub(_dust);


        round_[_rID].pot = _pot.add(_dust).add(round_[_rID].pot);


        _eventData_.genAmount = _gen.add(_eventData_.genAmount);
        _eventData_.potAmount = _pot;

        return(_eventData_);
    }





    function updateMasks(uint256 _rID, uint256 _pID, uint256 _gen, uint256 _keys)
        private
        returns(uint256)
    {












        uint256 _ppt = (_gen.mul(1000000000000000000)) / (round_[_rID].keys);
        round_[_rID].mask = _ppt.add(round_[_rID].mask);



        uint256 _pearn = (_ppt.mul(_keys)) / (1000000000000000000);
        plyrRnds_[_pID][_rID].mask = (((round_[_rID].mask.mul(_keys)) / (1000000000000000000)).sub(_pearn)).add(plyrRnds_[_pID][_rID].mask);


        return(_gen.sub((_ppt.mul(round_[_rID].keys)) / (1000000000000000000)));
    }





    function withdrawEarnings(uint256 _pID)
        private
        returns(uint256)
    {

        updateGenVault(_pID, plyr_[_pID].lrnd);


        uint256 _earnings = (plyr_[_pID].win).add(plyr_[_pID].gen).add(plyr_[_pID].aff);
        if (_earnings > 0)
        {
            plyr_[_pID].win = 0;
            plyr_[_pID].gen = 0;
            plyr_[_pID].aff = 0;
        }

        return(_earnings);
    }




    function endTx(uint256 _pID, uint256 _team, uint256 _eth, uint256 _keys, F3Ddatasets.EventReturns memory _eventData_)
