            l = 2;
        } else if(b < 0xF0) {
            l = 3;
        } else {
            l = 4;
        }


        if (l > self._len) {
            rune._len = self._len;
            self._ptr += self._len;
            self._len = 0;
            return rune;
        }

        self._ptr += l;
        self._len -= l;
        rune._len = l;
        return rune;
