                bytes32 hash;
                assembly { hash := sha3(needleptr, needlelen) }

                for (idx = 0; idx <= selflen - needlelen; idx++) {
                    bytes32 testHash;
                    assembly { testHash := sha3(ptr, needlelen) }
                    if (hash == testHash)
                        return ptr;
                    ptr += 1;
                }
            }
        }
        return selfptr + selflen;
    }



    function rfindPtr(uint selflen, uint selfptr, uint needlelen, uint needleptr) private pure returns (uint) {
        uint ptr;

        if (needlelen <= selflen) {
            if (needlelen <= 32) {
                bytes32 mask = bytes32(~(2 ** (8 * (32 - needlelen)) - 1));

                bytes32 needledata;
                assembly { needledata := and(mload(needleptr), mask) }

                ptr = selfptr + selflen - needlelen;
                bytes32 ptrdata;
                assembly { ptrdata := and(mload(ptr), mask) }

                while (ptrdata != needledata) {
                    if (ptr <= selfptr)
                        return selfptr;
                    ptr--;
                    assembly { ptrdata := and(mload(ptr), mask) }
                }
                return ptr + needlelen;
            } else {

                bytes32 hash;
                assembly { hash := sha3(needleptr, needlelen) }
                ptr = selfptr + (selflen - needlelen);
                while (ptr >= selfptr) {
                    bytes32 testHash;
                    assembly { testHash := sha3(ptr, needlelen) }
                    if (hash == testHash)
                        return ptr + needlelen;
                    ptr -= 1;
                }
            }
        }
        return selfptr;
    }









    function find(slice self, slice needle) internal pure returns (slice) {
        uint ptr = findPtr(self._len, self._ptr, needle._len, needle._ptr);
        self._len -= ptr - self._ptr;
        self._ptr = ptr;
        return self;
    }









    function rfind(slice self, slice needle) internal pure returns (slice) {
        uint ptr = rfindPtr(self._len, self._ptr, needle._len, needle._ptr);
        self._len = ptr - self._ptr;
        return self;
    }











    function split(slice self, slice needle, slice token) internal pure returns (slice) {
        uint ptr = findPtr(self._len, self._ptr, needle._len, needle._ptr);
        token._ptr = self._ptr;
        token._len = ptr - self._ptr;
        if (ptr == self._ptr + self._len) {

            self._len = 0;
        } else {
            self._len -= token._len + needle._len;
            self._ptr = ptr + needle._len;
        }
        return token;
    }










    function split(slice self, slice needle) internal pure returns (slice token) {
        split(self, needle, token);
    }











    function rsplit(slice self, slice needle, slice token) internal pure returns (slice) {
        uint ptr = rfindPtr(self._len, self._ptr, needle._len, needle._ptr);
        token._ptr = ptr;
        token._len = self._len - (ptr - self._ptr);
        if (ptr == self._ptr) {

            self._len = 0;
        } else {
            self._len -= token._len + needle._len;
        }
        return token;
    }










    function rsplit(slice self, slice needle) internal pure returns (slice token) {
        rsplit(self, needle, token);
    }







    function count(slice self, slice needle) internal pure returns (uint cnt) {
        uint ptr = findPtr(self._len, self._ptr, needle._len, needle._ptr) + needle._len;
        while (ptr <= self._ptr + self._len) {
            cnt++;
            ptr = findPtr(self._len - (ptr - self._ptr), ptr, needle._len, needle._ptr) + needle._len;
        }
    }







    function contains(slice self, slice needle) internal pure returns (bool) {
        return rfindPtr(self._len, self._ptr, needle._len, needle._ptr) != self._ptr;
    }








    function concat(slice self, slice other) internal pure returns (string) {
        string memory ret = new string(self._len + other._len);
        uint retptr;
        assembly { retptr := add(ret, 32) }
        memcpy(retptr, self._ptr, self._len);
        memcpy(retptr + self._len, other._ptr, other._len);
        return ret;
    }









    function join(slice self, slice[] parts) internal pure returns (string) {
        if (parts.length == 0)
            return "";

        uint length = self._len * (parts.length - 1);
        for(uint i = 0; i < parts.length; i++)
            length += parts[i]._len;

        string memory ret = new string(length);
        uint retptr;
        assembly { retptr := add(ret, 32) }

        for(i = 0; i < parts.length; i++) {
            memcpy(retptr, parts[i]._ptr, parts[i]._len);
            retptr += parts[i]._len;
            if (i < parts.length - 1) {
                memcpy(retptr, self._ptr, self._len);
                retptr += self._len;
            }
        }

        return ret;
    }
}






contract MyWill {

    using strings for *;


    address club;


    uint256 gasPrice;
    uint256 gasCost;


    address owner;


    string listWitnesses;


    string listHeirs;
    string listHeirsPercentages;


    mapping (string => bool) mapHeirsVoteOwnerHasDied;


    enum Status {CREATED, ALIVE, DEAD}
    Status status;


    event Deposit(address from, uint value);
    event SingleTransact(address owner, uint value, address to, bytes data);





    function MyWill (address _owner, string _listHeirs, string _listHeirsPercentages, string _listWitnesses, address _club, uint256 _gasPrice, uint256 _gasCost) {
        club = _club;
        owner = _owner;
        gasPrice = _gasPrice;
        gasCost = _gasCost;
        status = Status.CREATED;
        listHeirs = _listHeirs;
        listHeirsPercentages = _listHeirsPercentages;
        listWitnesses = _listWitnesses;


        var s = _listHeirsPercentages.toSlice().copy();
        var delim = ";".toSlice();
        var parts = new uint256[](s.count(delim) + 1);

        uint256 countPercentage;
        for(uint i = 0; i < parts.length; i++) {
            countPercentage = countPercentage + stringToUint(s.split(delim).toString());
        }

        require(countPercentage == 100000);
    }





    modifier onlyOwner() {
        require(msg.sender == owner);
        _;
    }

    modifier onlyAlive() {
        require(status == Status.ALIVE || status == Status.CREATED);
        _;
    }

    modifier onlyDead() {
        require(status == Status.DEAD);
        _;
    }

    modifier onlyHeir() {

        var s = listHeirs.toSlice().copy();
        var delim = ";".toSlice();
        string[] memory listOfHeirs = new string[](s.count(delim) + 1);
        bool itsHeir = false;

        string memory senderStringAddress = addressToString(msg.sender);

        for(uint i = 0; i < listOfHeirs.length; i++) {

            if(keccak256(senderStringAddress) == keccak256(s.split(delim).toString())){
                itsHeir = true;
                break;
            }
        }

        require(itsHeir);

        _;
    }

    modifier onlyWitness() {

        var s = listWitnesses.toSlice().copy();
        var delim = ";".toSlice();
        string[] memory arrayOfWitnesses = new string[](s.count(delim) + 1);
        bool itsWitness = false;

        string memory senderStringAddress = addressToString(msg.sender);

        for(uint i = 0; i < arrayOfWitnesses.length; i++) {

            if(keccak256(senderStringAddress) == keccak256(s.split(delim).toString())){
                itsWitness = true;
                break;
            }
        }

        require(itsWitness);

        _;
    }






    function () payable onlyAlive {
        if (status == Status.CREATED) {



            var witnessesList = listWitnesses.toSlice().copy();
            var witnessesLength = witnessesList.count(";".toSlice()) + 1;
            var needed = getWitnessWeiCost() * witnessesLength + getCreationWeiCost();
            require(msg.value > needed);


            club.transfer(getCreationWeiCost());


            for (uint i = 0; i < witnessesLength; i++) {
                var witnessAddress = parseAddr(witnessesList.split(";".toSlice()).toString());
                witnessAddress.transfer(getWitnessWeiCost());
            }


            status = Status.ALIVE;


            Deposit(msg.sender, msg.value);
        } else {
            Deposit(msg.sender, msg.value);
        }
    }


    function ownerDied() onlyWitness onlyAlive {

        require (this.balance > 0);


        mapHeirsVoteOwnerHasDied[addressToString(msg.sender)] = true;

        var users = listWitnesses.toSlice().copy();
        uint256 listLength = users.count(";".toSlice()) + 1;
        uint8 count = 0;

        for(uint i = 0; i < listLength; i++) {

            if(mapHeirsVoteOwnerHasDied[users.split(";".toSlice()).toString()] == true){
                count = count + 1;
            }
        }

        if(count == listLength){



            users = listHeirs.toSlice().copy();
            var  percentages = listHeirsPercentages.toSlice().copy();
            listLength = users.count(";".toSlice()) + 1;

            for(i = 0; i < listLength - 1; i++) {
                parseAddr(users.split(";".toSlice()).toString()).transfer(((this.balance * stringToUint(percentages.split(";".toSlice()).toString())) / 100000));
            }


            parseAddr(users.split(";".toSlice()).toString()).transfer(this.balance);

            status = Status.DEAD;
        }
    }





    function execute(address _to, uint _value, bytes _data) external onlyOwner {
        SingleTransact(msg.sender, _value, _to, _data);
        _to.call.value(_value)(_data);
    }





    function isOwner() returns (bool){
        return msg.sender == owner;
    }

    function getStatus() returns (Status){
        return status;
    }

    function getCreationWeiCost() returns (uint256) {
        return gasPrice * gasCost;
    }

    function getWitnessWeiCost() returns (uint256) {
        return (1000000 * gasPrice);
    }

    function getHeirs() returns (string, string) {
        return (listHeirs, listHeirsPercentages);
    }

    function getWitnesses() returns (string) {
        return listWitnesses;
    }

    function getWitnessesCount() returns (uint) {
        return listWitnesses.toSlice().copy().count(";".toSlice()) + 1;
    }

    function getBalance() constant returns (uint) {
        return  address(this).balance;
    }

    function hasVoted() returns (bool){
        return mapHeirsVoteOwnerHasDied[addressToString(msg.sender)];
    }





    function stringToUint(string s) constant private returns (uint result) {
        bytes memory b = bytes(s);
        uint i;
        result = 0;
        for (i = 0; i < b.length; i++) {
            uint c = uint(b[i]);
            if (c >= 48 && c <= 57) {
                result = result * 10 + (c - 48);
            }
        }
    }

    function addressToString(address x) private returns (string) {
        bytes memory s = new bytes(42);
        s[0] = "0";
        s[1] = "x";
        for (uint i = 0; i < 20; i++) {
            byte b = byte(uint8(uint(x) / (2**(8*(19 - i)))));
            byte hi = byte(uint8(b) / 16);
            byte lo = byte(uint8(b) - 16 * uint8(hi));
            s[2+2*i] = char(hi);
            s[2+2*i+1] = char(lo);
        }
        return string(s);
    }

    function char(byte b) private returns (byte c) {
        if (b < 10) return byte(uint8(b) + 0x30);
        else return byte(uint8(b) + 0x57);
    }


    function parseAddr(string _a) internal returns (address){
        bytes memory tmp = bytes(_a);
        uint160 iaddr = 0;
        uint160 b1;
        uint160 b2;
        for (uint i=2; i<2+2*20; i+=2){
            iaddr *= 256;
            b1 = uint160(tmp[i]);
            b2 = uint160(tmp[i+1]);
            if ((b1 >= 97)&&(b1 <= 102)) b1 -= 87;
            else if ((b1 >= 48)&&(b1 <= 57)) b1 -= 48;
            if ((b2 >= 97)&&(b2 <= 102)) b2 -= 87;
            else if ((b2 >= 48)&&(b2 <= 57)) b2 -= 48;
            iaddr += (b1*16+b2);
        }
        return address(iaddr);
    }


}

contract EthernameRaw is Managed {







  event Transfer(

    address indexed from,

    address indexed to,

    bytes32 indexed name

  );

  event Approval(

    address indexed owner,

    address indexed approved,

    bytes32 indexed name

  );

  event SendEther(

    address indexed from,

    address indexed to,

    bytes32 sender,

    bytes32 recipient,

    uint256 value

  );

  event Name(address indexed owner, bytes32 indexed name);

  event Price(bytes32 indexed name, uint256 price);

  event Buy(bytes32 indexed name, address buyer, uint256 price);

  event Attribute(bytes32 indexed name, bytes32 key);







  struct Record {

    address owner;

    uint256 price;

    mapping (bytes32 => bytes) attrs;

  }







  string public constant name = "Ethername";

  string public constant symbol = "ENM";



  mapping (address => bytes32) public ownerToName;

  mapping (bytes32 => Record) public nameToRecord;

  mapping (bytes32 => address) public nameToApproved;







  function rawRegister(bytes32 _name) public payable {

    _register(_name, msg.sender);

  }



  function rawTransfer(address _to, bytes32 _name)

    public

    onlyOwner(msg.sender, _name)

  {

    _transfer(msg.sender, _to, _name);

  }



  function rawApprove(address _to, bytes32 _name)

    public

    onlyOwner(msg.sender, _name)

  {

    _approve(msg.sender, _to, _name);

  }



  function rawTransferFrom(address _from, address _to, bytes32 _name)

    public

    onlyOwner(_from, _name)

    onlyApproved(msg.sender, _name)

  {

    _transfer(_from, _to, _name);

  }



  function rawSetPrice(bytes32 _name, uint256 _price)

    public

    onlyOwner(msg.sender, _name)

  {

    require(_price == uint256(uint128(_price)));

    nameToRecord[_name].price = _price;



    emit Price(_name, _price);

  }



  function rawBuy(bytes32 _name) public payable {

    Record memory _record = nameToRecord[_name];

    require(_record.price > 0);

    uint256 _price = _computePrice(_record.price);

    require(msg.value >= _price);



    _record.owner.transfer(_record.price);

    _transfer(_record.owner, msg.sender, _name);

    msg.sender.transfer(msg.value - _price);



    emit Buy(_name, msg.sender, _price);

  }



  function rawUseName(bytes32 _name) public onlyOwner(msg.sender, _name) {

    _useName(msg.sender, _name);

  }



  function rawSetAttribute(bytes32 _name, bytes32 _key, bytes _value)

    public

    onlyOwner(msg.sender, _name)

  {

    nameToRecord[_name].attrs[_key] = _value;



    emit Attribute(_name, _key);

  }



  function rawWipeAttributes(bytes32 _name, bytes32[] _keys)

    public

    onlyOwner(msg.sender, _name)

  {

    mapping (bytes32 => bytes) attrs = nameToRecord[_name].attrs;

		for (uint i = 0; i < _keys.length; i++) {

      delete attrs[_keys[i]];



      emit Attribute(_name, _keys[i]);

		}

  }



  function rawSendEther(bytes32 _name) public payable returns (bool _result) {

    address _to = nameToRecord[_name].owner;

    _result = (_name != bytes32(0)) &&

      (_to != address(0)) &&

      _to.send(msg.value);

    if (_result) {

      emit SendEther(

        msg.sender,

        _to,

        rawNameOf(msg.sender),

        _name,

        msg.value

      );

    }

  }







  function rawNameOf(address _address) public view returns (bytes32 _name) {

    _name = ownerToName[_address];

  }



  function rawOwnerOf(bytes32 _name) public view returns (address _owner) {

    _owner = nameToRecord[_name].owner;

  }



  function rawDetailsOf(bytes32 _name, bytes32 _key)

    public

    view

    returns (address _owner, uint256 _price, bytes _value)

  {

    _owner = nameToRecord[_name].owner;

    _price = _computePrice(nameToRecord[_name].price);

    _value = nameToRecord[_name].attrs[_key];

  }







  function _register(bytes32 _name, address _to) internal {

    require(nameToRecord[_name].owner == address(0));

		for (uint i = 0; i < _name.length; i++) {

		 	require((_name[i] == 0) ||

              (_name[i] > 96 && _name[i] < 123) ||

              (_name[i] > 47 && _name[i] < 58));

		}



    _transfer(0, _to, _name);

  }





  function _transfer(address _from, address _to, bytes32 _name) internal {

    address _null = address(0);



    if (nameToApproved[_name] != _null) {

      _approve(_from, _null, _name);

    }



    if (ownerToName[_from] == _name) {

      _useName(_from, 0);

    }



    nameToRecord[_name] = Record(_to, 0);



    if (ownerToName[_to] == bytes32(0)) {

      _useName(_to, _name);

    }



    emit Transfer(_from, _to, _name);

  }



  function _approve(address _owner, address _to, bytes32 _name) internal {

    nameToApproved[_name] = _to;

    emit Approval(_owner, _to, _name);

  }



  function _useName(address _owner, bytes32 _name) internal {

    ownerToName[_owner] = _name;

    emit Name(_owner, _name);

  }



  function _computePrice(uint256 _price) internal view returns (uint256) {

    return _price * (10000 + commission) / 10000;

  }



  function _stringToBytes32(string _string)

    internal

    pure

    returns (bytes32 _bytes32)

  {

    require(bytes(_string).length < 33);

    assembly {

      _bytes32 := mload(add(_string, 0x20))

    }

  }



  function _bytes32ToString(bytes32 _bytes32)

    internal

    pure

    returns (string _string)

  {

    assembly {

      let m := mload(0x40)

      mstore(m, 0x20)

      mstore(add(m, 0x20), _bytes32)

      mstore(0x40, add(m, 0x40))

      _string := m

    }

  }







  modifier onlyOwner(address _claimant, bytes32 _name) {

    require(nameToRecord[_name].owner == _claimant);

    _;

  }



  modifier onlyApproved(address _claimant, bytes32 _name) {

    require(nameToApproved[_name] == _claimant);

    _;

  }



}

