        ownerSetMaxProfitAsPercentOfHouse(10000);

        ownerSetMinBet(100000000000000000);        

        gasForOraclize = 300000;  

        oraclize_setCustomGasPrice(20000000000 wei);

        randomGenerateMethod = 0; 

