        onlyOwnerOrOperator
    {
        if(msg.sender == operator.addr && newHouseEdge > 990) throw;
        houseEdge = newHouseEdge;
    }




    function ownerSetMaxProfitAsPercentOfHouse(uint newMaxProfitAsPercent) public 
        onlyOwnerOrOperator
    {

