        maxPendingPayouts = safeSub(maxPendingPayouts, originalUserProfit);

        sendTo.transfer(originalUserBetValue);

        if(msg.sender == operator.addr){
            operator.refundAmtApprove = operator.refundAmtApprove -  originalUserBetValue;
