        returns(uint256)
    {

        uint256 _now = now;


        if (_now > round_[_rID].strt + rndGap_ && round_[_rID].eth != 0 && _now <= round_[_rID].end)
            return ( (round_[_rID].eth).keysRec(_eth) );
        else if (_now <= round_[_rID].end) 
            return ( (round_[_rID].ico).keysRec(_eth) );
        else 
            return ( (_eth).keys() );
